function (train_data, test_data, target_variable, nIter_values = c(1000,      2000, 3000), burnIn_values = c(300, 500, 700), thin_values = c(5,      10, 20))  {     if (!requireNamespace("BGLR", quietly = TRUE)) {         install.packages("BGLR")     }     library(BGLR)     train_data <- as.data.frame(train_data)     test_data <- as.data.frame(test_data)     X_train <- as.matrix(train_data[, !(names(train_data) %in%          target_variable), drop = FALSE])     y_train <- as.numeric(train_data[[target_variable]])     X_test <- as.matrix(test_data[, colnames(X_train), drop = FALSE])     best_rmse <- Inf     best_correlation <- -Inf     best_params <- NULL     best_predictions <- NULL     best_model <- NULL     param_grid <- expand.grid(nIter = nIter_values, burnIn = burnIn_values,          thin = thin_values)     for (i in 1:nrow(param_grid)) {         nIter <- param_grid$nIter[i]         burnIn <- param_grid$burnIn[i]         thin <- param_grid$thin[i]         bayesRidge_model <- BGLR(y = y_train, ETA = list(list(X = X_train,              model = "BRR")), nIter = nIter, burnIn = burnIn,              thin = thin, verbose = FALSE)         beta_estimates <- bayesRidge_model$ETA[[1]]$b         predictions <- as.numeric(X_test %*% beta_estimates)         actual_values <- as.numeric(test_data[[target_variable]])         rmse <- sqrt(mean((actual_values - predictions)^2))         correlation <- cor(predictions, actual_values, use = "complete.obs")         if (rmse < best_rmse || (rmse == best_rmse && correlation >              best_correlation)) {             best_rmse <- rmse             best_correlation <- correlation             best_params <- list(nIter = nIter, burnIn = burnIn,                  thin = thin)             best_predictions <- predictions             best_model <- bayesRidge_model         }     }     return(list(predictions = best_predictions, RMSE = best_rmse,          correlation = best_correlation, best_params = best_params,          model = best_model)) }